public void copyLine()
{
    FWFTextBlockInstance    sourceInstance, targetInstance;
    Common                  sourceRecord;

    next copyLine();

    sourceRecord = this.sourceRecord();

    if (salesQuotationCopying.parmCopyLineTextBlock())
    {
        //delete texts from setup
        delete_from targetInstance
            where targetInstance.RefTableId == salesQuotationLine.TableId
               && targetInstance.RefRecId   == salesQuotationLine.RecId;

        while select sourceInstance
            where sourceInstance.RefTableId == sourceRecord.TableId
               && sourceInstance.RefRecId   == sourceRecord.RecId
        {
            targetInstance = sourceInstance.copyToTarget(salesQuotationLine, true);
        }
    }
}
